public class Solution {
    public List<List<Integer>> combinationSum(int[] candidates, int target) {
        List<List<Integer>> result = new ArrayList<>();
        Arrays.sort(candidates);
        backtrack(candidates, target, 0, new ArrayList<>(), result);
        return result;
    }
    private void backtrack(int[] c, int rem, int start, List<Integer> curr, List<List<Integer>> res) {
        if (rem == 0) { res.add(new ArrayList<>(curr)); return; }
        for (int i = start; i < c.length && c[i] <= rem; i++) {
            curr.add(c[i]);
            backtrack(c, rem - c[i], i, curr, res); // i not i+1: allow reuse
            curr.remove(curr.size() - 1);
        }
    }
}

