public class Solution {
    public List<List<String>> solveNQueens(int n) {
        List<List<String>> result = new ArrayList<>();
        int[] queens = new int[n];
        Arrays.fill(queens, -1);
        Set<Integer> cols  = new HashSet<>(), d1 = new HashSet<>(), d2 = new HashSet<>();
        backtrack(n, 0, queens, cols, d1, d2, result);
        return result;
    }
    private void backtrack(int n, int row, int[] queens,
            Set<Integer> cols, Set<Integer> d1, Set<Integer> d2, List<List<String>> res) {
        if (row == n) { res.add(build(queens, n)); return; }
        for (int col = 0; col < n; col++) {
            if (cols.contains(col) || d1.contains(row-col) || d2.contains(row+col)) continue;
            queens[row] = col;
            cols.add(col); d1.add(row-col); d2.add(row+col);
            backtrack(n, row+1, queens, cols, d1, d2, res);
            queens[row] = -1;
            cols.remove(col); d1.remove(row-col); d2.remove(row+col);
        }
    }
    private List<String> build(int[] queens, int n) {
        List<String> board = new ArrayList<>();
        for (int q : queens) {
            char[] row = new char[n]; Arrays.fill(row, '.');
            row[q] = 'Q'; board.add(new String(row));
        }
        return board;
    }
}

