public class Solution {
    public List<List<String>> partition(String s) {
        int n = s.length();
        boolean[][] dp = new boolean[n][n];
        for (int i = 0; i < n; i++) dp[i][i] = true;
        for (int len = 2; len <= n; len++)
            for (int i = 0; i <= n - len; i++) {
                int j = i + len - 1;
                dp[i][j] = s.charAt(i) == s.charAt(j) && (len == 2 || dp[i+1][j-1]);
            }
        List<List<String>> result = new ArrayList<>();
        backtrack(s, 0, dp, new ArrayList<>(), result);
        return result;
    }
    private void backtrack(String s, int start, boolean[][] dp, List<String> curr, List<List<String>> res) {
        if (start == s.length()) { res.add(new ArrayList<>(curr)); return; }
        for (int end = start; end < s.length(); end++) {
            if (!dp[start][end]) continue;
            curr.add(s.substring(start, end + 1));
            backtrack(s, end + 1, dp, curr, res);
            curr.remove(curr.size() - 1);
        }
    }
}

