public class Solution {
    private boolean[][] rows = new boolean[9][10],
                         cols = new boolean[9][10],
                         boxes = new boolean[9][10];

    public void solveSudoku(char[][] board) {
        // Initialize tracking arrays from existing numbers
        for (int r = 0; r < 9; r++) for (int c = 0; c < 9; c++) {
            if (board[r][c] != '.') {
                int d = board[r][c] - '0', box = (r/3)*3 + c/3;
                rows[r][d] = cols[c][d] = boxes[box][d] = true;
            }
        }
        solve(board, 0, 0);
    }

    private boolean solve(char[][] board, int r, int c) {
        if (r == 9) return true;  // all rows done
        int nextr = (c == 8) ? r + 1 : r;
        int nextc = (c == 8) ? 0 : c + 1;
        if (board[r][c] != '.') return solve(board, nextr, nextc);
        int box = (r/3)*3 + c/3;
        for (int d = 1; d <= 9; d++) {
            if (rows[r][d] || cols[c][d] || boxes[box][d]) continue;
            board[r][c] = (char)('0' + d);
            rows[r][d] = cols[c][d] = boxes[box][d] = true;
            if (solve(board, nextr, nextc)) return true;
            board[r][c] = '.';
            rows[r][d] = cols[c][d] = boxes[box][d] = false;
        }
        return false;
    }
}

