public class Solution {
    private static final int[][] MOVES = {{2,1},{1,2},{-1,2},{-2,1},{-2,-1},{-1,-2},{1,-2},{2,-1}};

    public int[][] knightTour(int n, int startRow, int startCol) {
        int[][] board = new int[n][n];
        board[startRow][startCol] = 1;
        if (solve(board, startRow, startCol, 2, n)) return board;
        return new int[0][0]; // no solution
    }

    private boolean solve(int[][] board, int r, int c, int step, int n) {
        if (step == n * n + 1) return true;
        // Warnsdorff: sort moves by fewest onward options
        int[][] moves = MOVES.clone();
        Arrays.sort(moves, Comparator.comparingInt(m -> countMoves(board, r+m[0], c+m[1], n)));
        for (int[] m : moves) {
            int nr = r + m[0], nc = c + m[1];
            if (isValid(board, nr, nc, n)) {
                board[nr][nc] = step;
                if (solve(board, nr, nc, step + 1, n)) return true;
                board[nr][nc] = 0;
            }
        }
        return false;
    }
    private int countMoves(int[][] board, int r, int c, int n) {
        int count = 0;
        for (int[] m : MOVES) { int nr=r+m[0], nc=c+m[1]; if (isValid(board,nr,nc,n)) count++; }
        return count;
    }
    private boolean isValid(int[][] b, int r, int c, int n) {
        return r>=0 && c>=0 && r<n && c<n && b[r][c]==0;
    }
}
